sys_ws_operation.operation_script:
(function(request, response) {
        try {
          var body = request.body;
          var data = body ? body.data : null;
          if (!data || !data.table) {
            response.setStatus(400);
            response.setBody(JSON.stringify({ error: 'Missing table parameter' }));
            return;
          }
          var results = [];
          var gr = new GlideRecord(data.table);
          if (!gr.isValid()) {
            response.setStatus(400);
            response.setBody(JSON.stringify({ error: 'Table not accessible: ' + data.table }));
            return;
          }
          if (data.query) gr.addEncodedQuery(data.query);
          gr.setLimit(data.limit || 25);
          gr.query();
          var fields = data.fields || ['sys_id','name','sys_class_name'];
          while (gr.next()) {
            var rec = {};
            for (var i = 0; i < fields.length; i++) {
              rec[fields[i]] = gr.getDisplayValue(fields[i]) || gr.getValue(fields[i]) || '';
            }
            rec.sys_id = gr.getUniqueValue();
            results.push(rec);
          }
          response.setStatus(200);
          response.setBody(JSON.stringify({ table: data.table, count: results.length, records: results }));
        } catch(ex) {
          response.setStatus(500);
          response.setBody(JSON.stringify({ error: ex.message || 'Query failed' }));
        }
      })(request, response);
